import{_ as n,o as t,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"69F. Occupational Violence And Aggression Prevention And","description":"","frontmatter":{"title":"69F. Occupational Violence And Aggression Prevention And","eba":"Mental Health Services 2024-2028","topics":["ohs","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/ohs/69F-occupational-violence-and-aggression-prevention-and.md","filePath":"ebas/mental-health/common-terms/ohs/69F-occupational-violence-and-aggression-prevention-and.md"}'),a={name:"ebas/mental-health/common-terms/ohs/69F-occupational-violence-and-aggression-prevention-and.md"};function s(r,e,p,l,c,g){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="_69f-occupational-violence-and-aggression-prevention-and" tabindex="-1">69F. Occupational Violence And Aggression Prevention And <a class="header-anchor" href="#_69f-occupational-violence-and-aggression-prevention-and" aria-label="Permalink to &quot;69F. Occupational Violence And Aggression Prevention And&quot;">​</a></h1><p>Management</p><p><strong>69F.1</strong> Prevention and Management of Occupational Violence and Aggression Employees are entitled to be provided a workplace free of occupational violence and aggression (OVA).</p><p><strong>69F.2</strong> Occupational Violence and Aggression Prevention</p><p><strong>(a)</strong> VHIA, Employers, Unions and Employees support action to end violence and aggression in Victoria’s public health system. This requires an inclusive, integrated approach both at an industry and individual health service level.</p><p><strong>(b)</strong> Each Employer will have an action plan, which will be subject to ongoing review, to address occupational violence and aggression.</p><p><strong>(c)</strong> Any action plan will:</p><p><strong>(i)</strong> outline the actions necessary to improve security</p><p><strong>(ii)</strong> implement proactive measures to identify and address risks</p><p><strong>(iii)</strong> ensure a reporting culture and mechanisms to assist in investigation; and</p><p><strong>(iv)</strong> provide appropriate support following workplace incidents.</p><p><strong>(d)</strong> The action plan will be consistent with the:</p><p><strong>(i)</strong> Occupational Violence Principles</p><p><strong>(ii)</strong> WorkSafe Guidance note relevant to occupational violence and aggression.</p><p><strong>(e)</strong> In developing or reviewing an action plan the Employer will consult with HSRs, workplace delegates, the Unions and affected employees to identify any gaps having regard for the requirements at (c).</p><p><strong>(f)</strong> The Employer will designate an Occupational Health and Safety committee (which may be an existing committee) as responsible for overseeing the actions required by this clause.</p><p><strong>(g)</strong> Upon written request from either Union, an Employer will provide to the requesting Union the following written information within four (4) weeks:</p><p><strong>(i)</strong> the Employer’s action plan or, where it does not have one, how it is developing an action plan,</p><p><strong>(ii)</strong> the name of the Committee responsible for oversight of occupational violence and aggression issues including the contact details of the Committee Chairperson,</p><p><strong>(iii)</strong> where the Committee at (ii) establishes a sub-committee or working party for the purpose of giving effect to the obligations under this clause, the name of the sub-committee or working party and the contact details of the Chairperson, and</p><p><strong>(iv)</strong> details of the Employer’s program / system for addressing occupational violence and aggression including relevant policies, and</p><p><strong>(v)</strong> other material relevant to the Employer’s program / system for addressing occupational violence and aggression and / or action plan.</p><p><strong>(h)</strong> Upon request by either Union, the Employer will invite the requesting Union to attend and participate in meetings of the relevant committee established or convened for the purpose of giving effect to this clause.</p><p><strong>69F.3</strong> Employer Policies</p><p><strong>(a)</strong> Each Employer will have and maintain policies that directly address the prevention and management of occupational violence and aggression will:</p><p><strong>(i)</strong> regularly (at least every 12 months) review the policy / policies through the OHS committee(s) (including HSRs) and OHS consultation mechanisms applying at the Employer, with specific consideration to an OHS Risk Management approach, and the Occupational Violence Principles to prevent violence and aggression</p><p><strong>(ii)</strong> ensure that Employees are provided with the policies and are advised of any change</p><p><strong>(iii)</strong> ensure that Employees receive periodic refresher training regarding occupational violence and aggression issues including the policies</p><p><strong>(iv)</strong> upon request, provide a copy of existing policies to Unions or another Employee representative; and</p><p><strong>(v)</strong> upon request, meet with the Unions or other Employee representative for consultation regarding the policies, their application and implementation.</p><p><strong>69F.4</strong> Nothing in this clause limits an Employer from doing anything to support the reduction and prevention of occupational violence and aggression.</p><p><strong>69F.5</strong> Key Principles In developing, reviewing and implementing policies, the following matters will be considered:</p><p><strong>(a)</strong> security;</p><p><strong>(b)</strong> risk identification</p><p><strong>(c)</strong> the development of consumer care plans</p><p><strong>(d)</strong> incident reporting, investigation and action</p><p><strong>(e)</strong> workplace design</p><p><strong>(f)</strong> training</p><p><strong>(g)</strong> integration of policies and procedures</p><p><strong>(h)</strong> post incident support</p><p><strong>(i)</strong> application across all health disciplines; and</p><p><strong>(j)</strong> empowering staff to expect a safe workplace.</p><p><strong>69F.6</strong> Continuous Improvement</p><p><strong>(a)</strong> The Employer will undertake regular (at least six-monthly) audits of their occupational violence and aggression management strategy, considering the Occupational Violence Principles to end violence and aggression, in consultation with HSRs and clinical care staff.</p><p><strong>(b)</strong> The Employer will provide the results of such audits and the action plan to their HSR and, upon request, Job Representatives for review and discussion at the Committee or working group referred to at clauses 69F.2(f) and 69D.</p><p><strong>(c)</strong> Further external developments regarding the prevention and management of occupational violence and aggression will occur during the life of the Agreement. They may include but not be limited to:</p><p><strong>(i)</strong> baseline standards for security; and</p><p><strong>(ii)</strong> incident reporting systems.</p><p><strong>(d)</strong> Employers will continue to review, consult and update their response to occupational violence and aggression to take into account developments that may result in the continued improvement of its response.</p><p><strong>69F.7</strong> OVA Reporting</p><p><strong>(a)</strong> The Employer will make available to the committee designated at clause 69F.5(f) the following information:</p><p><strong>(i)</strong> The number of code greys and code black and other alerts relating to risk of violence</p><p><strong>(ii)</strong> The overall number of reported incidents of OVA</p><p><strong>(iii)</strong> The number of incidents that have resulted in injury (which may be physical or psychological) to staff, consumers and visitors and the number of incidents that have resulted in property damage; where available; and</p><p><strong>(iv)</strong> Systemic recommendations and actions affecting risk management and OVA.</p><p><strong>(b)</strong> The Employer will, in consultation with the elected HSRs conduct workplace violence audits of mental health and wellbeing facilities.</p><p><strong>(c)</strong> Opportunities will be provided during meetings of the OHS consultative committees designated at clause 69F.2(f)to discuss these matters.</p>',57)])])}const m=n(a,[["render",s]]);export{h as __pageData,m as default};
